'use client';

import { useEffect, useRef } from 'react';

export default function QuantumBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    canvas.width = width;
    canvas.height = height;

    const particles: Particle[] = [];
    const particleCount = Math.min(width / 8, 150); // density control
    let scrollY = 0;
    
    // Track mouse
    let mouse = { x: -1000, y: -1000 };
    let targetMouse = { x: -1000, y: -1000 };

    class Particle {
      x: number;
      y: number;
      z: number;
      vx: number;
      vy: number;
      baseSize: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.z = Math.random() * 1000 + 100; // Depth
        this.vx = (Math.random() - 0.5) * 0.5;
        this.vy = (Math.random() - 0.5) * 0.5;
        this.baseSize = Math.random() * 1.5 + 0.5;
      }

      update() {
        this.x += this.vx;
        this.y += this.vy;

        // Space warp based on scroll speed
        this.z -= (scrollY * 0.05);
        if (this.z < 10) this.z = 1000;
        if (this.z > 1500) this.z = 100;

        // Bounce
        if (this.x < 0 || this.x > width) this.vx *= -1;
        if (this.y < 0 || this.y > height) this.vy *= -1;
      }

      draw() {
        if (!ctx) return;
        const scale = 500 / this.z;
        const screenX = (this.x - width / 2) * scale + width / 2;
        const screenY = (this.y - height / 2) * scale + height / 2;
        const size = this.baseSize * scale;

        // Mouse interaction
        const dx = screenX - mouse.x;
        const dy = screenY - mouse.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        
        let opacity = 0.3 * scale;
        if (dist < 150) opacity += (150 - dist) / 150; // Glow near mouse

        ctx.beginPath();
        ctx.arc(screenX, screenY, size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(139, 147, 255, ${Math.min(opacity, 1)})`;
        ctx.fill();

        return { screenX, screenY, scale, opacity };
      }
    }

    for (let i = 0; i < particleCount; i++) {
        particles.push(new Particle());
    }

    const connectActiveParticles = (renderedData: any[]) => {
      for (let i = 0; i < renderedData.length; i++) {
        for (let j = i + 1; j < renderedData.length; j++) {
          const p1 = renderedData[i];
          const p2 = renderedData[j];

          const dx = p1.screenX - p2.screenX;
          const dy = p1.screenY - p2.screenY;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < 120) {
             const mDx = ((p1.screenX + p2.screenX)/2) - mouse.x;
             const mDy = ((p1.screenY + p2.screenY)/2) - mouse.y;
             const mDist = Math.sqrt(mDx * mDx + mDy * mDy);
             
             let alpha = Math.min((120 - dist) / 120, 0.4);
             if (mDist < 200) {
                 alpha += (200 - mDist) / 400; // Brighter lines near mouse
                 ctx!.strokeStyle = `rgba(56, 189, 248, ${alpha})`;
             } else {
                 ctx!.strokeStyle = `rgba(255, 255, 255, ${alpha * 0.3})`;
             }

             ctx!.lineWidth = 1;
             ctx!.beginPath();
             ctx!.moveTo(p1.screenX, p1.screenY);
             ctx!.lineTo(p2.screenX, p2.screenY);
             ctx!.stroke();
          }
        }
      }
    };

    let animationFrameId: number;

    const render = () => {
      mouse.x += (targetMouse.x - mouse.x) * 0.1;
      mouse.y += (targetMouse.y - mouse.y) * 0.1;

      ctx.clearRect(0, 0, width, height);

      const renderedData = [];
      for (let i = 0; i < particles.length; i++) {
        particles[i].update();
        renderedData.push(particles[i].draw());
      }
      
      connectActiveParticles(renderedData);
      
      // Decay scroll velocity to stand-still over time
      scrollY *= 0.95; 
      
      animationFrameId = requestAnimationFrame(render);
    };

    render();

    // Event Listeners
    const handleResize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
    };

    const handleMouseMove = (e: MouseEvent) => {
        targetMouse.x = e.clientX;
        targetMouse.y = e.clientY;
    };
    
    let lastScroll = window.scrollY;
    const handleScroll = () => {
      const current = window.scrollY;
      const delta = current - lastScroll;
      scrollY += delta;
      lastScroll = current;
    };

    window.addEventListener('resize', handleResize);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('scroll', handleScroll);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 -z-20 h-screen w-screen bg-[#020202]"
    />
  );
}
